values
  ('grep-error-log', 'grep', 'Как найти строки с текстом error в файле app.log?', 'Нужны шаблон в кавычках и имя файла.', 'grep "error" app.log', ARRAY['grep ''error'' app.log', 'grep error app.log']::text[], 'Например, так быстро ищут ошибки в `app.log` после падения сервиса.', 'Search', 'easy'),
  ('pwd-current-dir', 'pwd', 'Как показать текущую директорию в терминале?', 'Это короткая команда из трех букв.', 'pwd', ARRAY[]::text[], 'Полезно перед копированием файлов, чтобы убедиться, где вы сейчас находитесь.', 'Navigation', 'easy'),
  ('ls-hidden-files', 'ls', 'Как показать файлы, включая скрытые, в текущей папке?', 'Нужен флаг для hidden entries.', 'ls -la', ARRAY['ls -al']::text[], 'Так можно увидеть `.env`, `.gitignore` и другие скрытые файлы проекта.', 'File Management', 'easy'),
  ('cd-parent', 'cd', 'Как перейти на один уровень выше?', 'Используется специальная ссылка на родительский каталог.', 'cd ..', ARRAY[]::text[], 'Если вы в `/var/log/nginx`, команда вернет вас в `/var/log`.', 'Navigation', 'easy'),
  ('chmod-script', 'chmod', 'Как дать владельцу право на выполнение файла deploy.sh?', 'Используется флаг +x.', 'chmod +x deploy.sh', ARRAY[]::text[], 'После этого скрипт можно запускать как `./deploy.sh`.', 'Permissions', 'medium'),
  ('find-nginx-conf', 'find', 'Как найти файл nginx.conf начиная с /etc?', 'Нужны стартовая директория, фильтр по имени и имя файла.', 'find /etc -name nginx.conf', ARRAY['find /etc -name "nginx.conf"', 'find /etc -name ''nginx.conf''']::text[], 'Удобно, если конфиг лежит не там, где вы ожидали.', 'Search', 'medium'),
  ('tail-follow-log', 'tail', 'Как следить за обновлением файла server.log в реальном времени?', 'Используется флаг follow.', 'tail -f server.log', ARRAY[]::text[], 'Часто так смотрят live-логи приложения во время деплоя.', 'System Monitoring', 'easy'),
  ('ps-node-processes', 'ps', 'Как найти процессы, связанные с node?', 'Команду ps часто объединяют с grep.', 'ps aux | grep node', ARRAY['ps aux|grep node']::text[], 'Помогает быстро найти зависший `node`-процесс на сервере.', 'Processes', 'medium'),
  ('systemctl-nginx-status', 'systemctl', 'Как проверить статус сервиса nginx?', 'После команды нужен подкомандный status и имя сервиса.', 'systemctl status nginx', ARRAY[]::text[], 'Так можно понять, запущен ли сервис и почему он не стартует.', 'Services', 'medium'),
  ('df-human', 'df', 'Как посмотреть использование диска в удобном для чтения формате?', 'Нужен human-readable режим.', 'df -h', ARRAY[]::text[], 'Когда раздел почти заполнен, эта команда сразу показывает размеры в GB и MB.', 'System Monitoring', 'easy'),
  ('ip-address', 'ip', 'Как показать IP-адреса сетевых интерфейсов?', 'Используется подкоманда address в короткой форме.', 'ip a', ARRAY['ip address']::text[], 'Полезно, когда нужно быстро узнать IP сервера или контейнера.', 'Networking', 'medium'),
  ('apt-update', 'apt', 'Как обновить список пакетов в Debian или Ubuntu?', 'Нужна подкоманда update, обычно через sudo.', 'sudo apt update', ARRAY[]::text[], 'Перед установкой пакетов обычно сначала обновляют индекс репозиториев.', 'Package Management', 'easy'),
  ('mkdir-parents', 'mkdir', 'Как создать папку logs и сразу вложенную archive, даже если logs еще нет?', 'Нужен флаг для создания промежуточных директорий.', 'mkdir -p logs/archive', ARRAY[]::text[], 'Удобно в setup-скриптах, где структура папок должна создаваться с нуля.', 'File Management', 'easy'),
  ('cp-recursive', 'cp', 'Как скопировать директорию config целиком в backup/config?', 'Для папок нужен рекурсивный режим.', 'cp -r config backup/config', ARRAY[]::text[], 'Так часто делают резервную копию конфигов перед изменениями.', 'File Management', 'medium'),
  ('mv-rename-file', 'mv', 'Как переименовать файл notes.txt в notes-old.txt?', 'Одна и та же команда и перемещает, и переименовывает.', 'mv notes.txt notes-old.txt', ARRAY[]::text[], 'Быстрый способ сохранить старую версию файла перед редактированием.', 'File Management', 'easy'),
  ('cat-file-content', 'cat', 'Как вывести содержимое файла .env на экран?', 'Команда просто печатает содержимое файла в терминал.', 'cat .env', ARRAY[]::text[], 'Подходит для коротких файлов, которые нужно быстро проверить.', 'File Management', 'easy'),
  ('grep-recursive-todo', 'grep', 'Как найти все вхождения TODO внутри папки src?', 'Нужен рекурсивный поиск по каталогу.', 'grep -R "TODO" src', ARRAY['grep -R ''TODO'' src', 'grep -R TODO src', 'grep -r TODO src']::text[], 'Полезно перед релизом, чтобы найти оставшиеся заметки в коде.', 'Search', 'medium'),
  ('find-log-files', 'find', 'Как найти все файлы с расширением .log в текущей папке и ниже?', 'Нужен поиск по типу файла и шаблону имени.', 'find . -type f -name "*.log"', ARRAY['find . -type f -name ''*.log''']::text[], 'Так можно быстро собрать все логи проекта для анализа или очистки.', 'Search', 'medium'),
  ('chown-user-group', 'chown', 'Как назначить владельцем и группой для файла app.conf пользователя deploy?', 'Нужно указать `пользователь:группа` перед именем файла.', 'chown deploy:deploy app.conf', ARRAY[]::text[], 'Часто применяют после копирования конфигов от root к сервисному пользователю.', 'Permissions', 'medium'),
  ('chmod-readonly-file', 'chmod', 'Как выдать файлу config.yml права 644?', 'Используется числовая запись прав доступа.', 'chmod 644 config.yml', ARRAY[]::text[], 'Это типичный режим для конфигов, которые не должны быть исполняемыми.', 'Permissions', 'medium'),
  ('top-cpu-usage', 'top', 'Как открыть интерактивный монитор процессов и нагрузки?', 'Это короткая встроенная утилита без дополнительных флагов.', 'top', ARRAY[]::text[], 'Полезно, когда сервер начинает тормозить и нужно увидеть лидеров по CPU.', 'Processes', 'easy'),
  ('kill-process', 'kill', 'Как завершить процесс с PID 4242 обычным сигналом TERM?', 'Достаточно указать команду и сам PID.', 'kill 4242', ARRAY[]::text[], 'Так мягко останавливают зависший процесс перед более жесткими мерами.', 'Processes', 'medium'),
  ('free-memory', 'free', 'Как посмотреть использование оперативной памяти в человекочитаемом виде?', 'Нужен тот же флаг, что и у `df` для удобного формата.', 'free -h', ARRAY[]::text[], 'Команда помогает понять, заканчивается ли RAM на машине.', 'System Monitoring', 'easy'),
  ('du-directory-size', 'du', 'Как узнать суммарный размер папки uploads в удобном формате?', 'Нужны краткий итог и human-readable вывод.', 'du -sh uploads', ARRAY[]::text[], 'Так можно быстро найти тяжелую директорию без длинного списка по файлам.', 'System Monitoring', 'medium'),
  ('ss-listening-ports', 'ss', 'Как показать все слушающие TCP и UDP порты с процессами?', 'Нужны флаги для listening sockets, обоих протоколов и имен процессов.', 'ss -tulpn', ARRAY['ss -lntup', 'ss -lupnt', 'ss -ltnup']::text[], 'Удобно, когда нужно понять, какой процесс занял нужный порт.', 'Networking', 'hard'),
  ('ping-check-host', 'ping', 'Как отправить 4 ICMP-запроса на 8.8.8.8?', 'Нужен флаг для ограничения количества пакетов.', 'ping -c 4 8.8.8.8', ARRAY[]::text[], 'Это быстрый способ проверить базовую сетевую доступность.', 'Networking', 'easy'),
  ('curl-head-request', 'curl', 'Как получить только HTTP-заголовки от https://example.com?', 'Нужен HEAD-запрос коротким флагом.', 'curl -I https://example.com', ARRAY['curl --head https://example.com']::text[], 'Полезно для проверки статуса сайта и заголовков без скачивания тела ответа.', 'Networking', 'medium'),
  ('systemctl-restart-nginx', 'systemctl', 'Как перезапустить сервис nginx?', 'Используется подкоманда restart, обычно через sudo.', 'sudo systemctl restart nginx', ARRAY[]::text[], 'Обычно это делают после правок в конфиге и проверки `nginx -t`.', 'Services', 'easy'),
  ('journalctl-follow-service', 'journalctl', 'Как смотреть логи сервиса nginx в реальном времени через systemd?', 'Нужны флаги для фильтра по юниту и follow-режима.', 'journalctl -u nginx -f', ARRAY['journalctl --unit nginx -f']::text[], 'Очень удобно на системах, где сервис пишет логи не в файл, а в journal.', 'Services', 'hard'),
  ('apt-install-package', 'apt', 'Как установить пакет htop в Debian или Ubuntu?', 'После update обычно используют подкоманду install.', 'sudo apt install htop', ARRAY[]::text[], 'Это типичный сценарий, когда на сервер нужно быстро поставить утилиту мониторинга.', 'Package Management', 'easy'),
  ('apt-upgrade-packages', 'apt', 'Как обновить уже установленные пакеты до новых версий?', 'Используется подкоманда upgrade, как правило через sudo.', 'sudo apt upgrade', ARRAY[]::text[], 'Так накатывают обновления безопасности после обновления индекса пакетов.', 'Package Management', 'medium'),
  ('whoami-current-user', 'whoami', 'Как показать имя текущего пользователя?', 'Команда отвечает одной строкой без дополнительных флагов.', 'whoami', ARRAY[]::text[], 'Полезно быстро проверить, под кем вы вошли на сервер или в контейнер.', 'Users', 'easy'),
  ('hostname-show', 'hostname', 'Как показать имя текущего хоста?', 'Команда совпадает с самим термином для имени машины.', 'hostname', ARRAY[]::text[], 'Удобно, когда вы подключены к нескольким серверам и хотите понять, где сейчас находитесь.', 'Networking', 'easy'),
  ('uname-kernel', 'uname', 'Как показать версию ядра Linux?', 'Нужен флаг для kernel release.', 'uname -r', ARRAY[]::text[], 'Так быстро проверяют, на какой версии ядра работает система после обновления.', 'System Info', 'easy'),
  ('which-python', 'which', 'Как узнать, какой исполняемый файл будет запущен для команды python3?', 'После команды нужно указать само имя бинарника.', 'which python3', ARRAY[]::text[], 'Полезно, когда в системе несколько интерпретаторов и нужно понять, какой стоит в PATH.', 'System Info', 'easy'),
  ('touch-create-file', 'touch', 'Как создать пустой файл notes.txt?', 'Команда создает файл, если его еще нет.', 'touch notes.txt', ARRAY[]::text[], 'Так можно быстро создать заготовку под конфиг, скрипт или заметки.', 'File Management', 'easy'),
  ('rm-delete-file', 'rm', 'Как удалить файл notes.txt?', 'Используется базовая команда удаления без дополнительных флагов.', 'rm notes.txt', ARRAY[]::text[], 'Подходит для удаления одиночного временного файла.', 'File Management', 'easy'),
  ('rm-remove-dir-recursive', 'rm', 'Как удалить директорию cache вместе со всем ее содержимым?', 'Нужен рекурсивный режим удаления.', 'rm -r cache', ARRAY[]::text[], 'Так часто очищают временные каталоги сборки или кэша.', 'File Management', 'medium'),
  ('rmdir-empty-dir', 'rmdir', 'Как удалить пустую директорию empty-dir?', 'Команда работает только с пустыми папками.', 'rmdir empty-dir', ARRAY[]::text[], 'Хорошо подходит, когда нужно аккуратно убрать уже пустой каталог.', 'File Management', 'easy'),
  ('ln-symlink', 'ln', 'Как создать символическую ссылку current.log на файл app.log?', 'Нужен флаг для symbolic link и затем target с именем ссылки.', 'ln -s app.log current.log', ARRAY[]::text[], 'Удобно, когда нужно дать стабильное имя для часто меняющегося файла.', 'File Management', 'medium'),
  ('tar-create-gz', 'tar', 'Как упаковать директорию project в архив project.tar.gz?', 'Нужны флаги для create, gzip и имени выходного файла.', 'tar -czf project.tar.gz project', ARRAY[]::text[], 'Так обычно делают архив проекта перед переносом или бэкапом.', 'Archives', 'medium'),
  ('tar-extract-gz', 'tar', 'Как распаковать архив backup.tar.gz в текущую папку?', 'Нужны флаги для extract, gzip и имени архива.', 'tar -xzf backup.tar.gz', ARRAY[]::text[], 'Это стандартный способ развернуть tar.gz-архив на сервере.', 'Archives', 'medium'),
  ('gzip-file', 'gzip', 'Как сжать файл server.log в server.log.gz?', 'Команда сама заменит исходный файл на сжатую версию.', 'gzip server.log', ARRAY[]::text[], 'Полезно, когда нужно быстро сжать большой лог и освободить место.', 'Archives', 'easy'),
  ('gunzip-file', 'gunzip', 'Как распаковать файл server.log.gz обратно?', 'Используется парная команда к gzip.', 'gunzip server.log.gz', ARRAY[]::text[], 'Так можно быстро вернуть содержимое сжатого лога для чтения или анализа.', 'Archives', 'easy'),
  ('head-first-lines', 'head', 'Как показать первые 20 строк файла app.log?', 'Нужен числовой флаг для количества строк.', 'head -n 20 app.log', ARRAY['head -20 app.log']::text[], 'Полезно для быстрого просмотра начала файла без открытия всего содержимого.', 'Text Processing', 'easy'),
  ('tail-last-lines', 'tail', 'Как показать последние 50 строк файла app.log?', 'Нужен флаг с числом строк.', 'tail -n 50 app.log', ARRAY['tail -50 app.log']::text[], 'Так часто смотрят свежие события в логах после ошибки или рестарта сервиса.', 'Text Processing', 'easy'),
  ('less-open-file', 'less', 'Как открыть файл app.log для постраничного просмотра в терминале?', 'Команда сама открывает файл без флагов.', 'less app.log', ARRAY[]::text[], 'Подходит для длинных файлов, когда cat уже слишком шумный.', 'Text Processing', 'easy'),
  ('wc-lines-file', 'wc', 'Как посчитать количество строк в файле access.log?', 'Нужен флаг lines.', 'wc -l access.log', ARRAY[]::text[], 'Полезно быстро оценить размер файла по количеству записей.', 'Text Processing', 'easy'),
  ('sort-file', 'sort', 'Как отсортировать строки файла names.txt по алфавиту?', 'Команда принимает имя файла без дополнительных обязательных флагов.', 'sort names.txt', ARRAY[]::text[], 'Удобно, когда нужно быстро упорядочить список или подготовить его для diff.', 'Text Processing', 'easy'),
  ('uniq-duplicates', 'uniq', 'Как убрать подряд идущие дубликаты из файла list.txt?', 'Команда работает с уже отсортированным или сгруппированным текстом.', 'uniq list.txt', ARRAY[]::text[], 'Часто используют после sort, чтобы собрать уникальные значения.', 'Text Processing', 'medium'),
  ('cut-first-field-colon', 'cut', 'Как вывести только первый столбец из файла users.txt, где поля разделены двоеточием?', 'Нужны delimiter и номер поля.', 'cut -d '':'' -f1 users.txt', ARRAY['cut -d: -f1 users.txt']::text[], 'Так можно быстро достать логины из файла формата, похожего на /etc/passwd.', 'Text Processing', 'medium'),
  ('sed-replace-localhost', 'sed', 'Как заменить все вхождения localhost на 127.0.0.1 в файле app.conf и вывести результат в терминал?', 'Нужна подстановка формата s/old/new/g.', 'sed ''s/localhost/127.0.0.1/g'' app.conf', ARRAY['sed "s/localhost/127.0.0.1/g" app.conf']::text[], 'Полезно перед ручной правкой, чтобы проверить, как будет выглядеть результат замены.', 'Text Processing', 'hard'),
  ('awk-print-first-column', 'awk', 'Как вывести первый столбец из файла data.txt?', 'Нужно короткое действие print с `$1`.', 'awk ''{print $1}'' data.txt', ARRAY['awk "{print $1}" data.txt']::text[], 'Команда полезна, когда нужно быстро вытащить первую колонку из табличного текста.', 'Text Processing', 'hard'),
  ('xargs-rm-tmp', 'xargs', 'Как удалить файлы, перечисленные построчно в файле files.txt?', 'Список читается из stdin и передается в rm.', 'cat files.txt | xargs rm', ARRAY[]::text[], 'Так можно пакетно удалить много файлов, если их имена уже собраны в отдельный список.', 'Text Processing', 'hard'),
  ('tee-save-output', 'tee', 'Как сохранить вывод команды ls -la в файл listing.txt и одновременно показать его в терминале?', 'Нужен pipe и команда tee.', 'ls -la | tee listing.txt', ARRAY[]::text[], 'Полезно, когда нужно и увидеть результат сразу, и сохранить его для отчета.', 'Text Processing', 'medium'),
  ('env-show-vars', 'env', 'Как вывести все переменные окружения?', 'Команда печатает окружение без дополнительных параметров.', 'env', ARRAY[]::text[], 'Так можно быстро проверить PATH, HOME, SHELL и другие переменные процесса.', 'Shell', 'easy'),
  ('export-var', 'export', 'Как установить переменную окружения NODE_ENV со значением production в текущей сессии?', 'Нужно имя, знак равно и значение без пробелов.', 'export NODE_ENV=production', ARRAY[]::text[], 'Часто так временно переключают режим запуска приложения в терминале.', 'Shell', 'easy'),
  ('echo-path', 'echo', 'Как вывести значение переменной PATH?', 'После echo нужно обратиться к переменной через знак доллара.', 'echo $PATH', ARRAY[]::text[], 'Это помогает понять, из каких каталогов система ищет исполняемые файлы.', 'Shell', 'easy'),
  ('passwd-current-user', 'passwd', 'Как запустить смену пароля для текущего пользователя?', 'Команда вызывается без аргументов.', 'passwd', ARRAY[]::text[], 'Так пользователь может вручную поменять свой пароль на Linux-машине.', 'Users', 'easy'),
  ('sudo-run-root', 'sudo', 'Как выполнить команду apt update с правами root?', 'Нужно поставить sudo перед обычной командой.', 'sudo apt update', ARRAY[]::text[], 'Это один из самых частых сценариев при администрировании Ubuntu или Debian.', 'Users', 'easy'),
  ('useradd-create-user', 'useradd', 'Как создать нового пользователя deploy с домашней директорией?', 'Нужен флаг для создания home directory.', 'sudo useradd -m deploy', ARRAY[]::text[], 'Так часто заводят отдельного сервисного пользователя под деплой или приложение.', 'Users', 'medium'),
  ('usermod-add-sudo-group', 'usermod', 'Как добавить пользователя deploy в группу sudo?', 'Нужны флаги append и groups.', 'sudo usermod -aG sudo deploy', ARRAY[]::text[], 'Полезно, когда нужно выдать пользователю админские права без логина под root.', 'Users', 'hard'),
  ('id-show-user-groups', 'id', 'Как показать UID, GID и группы пользователя deploy?', 'Команде достаточно передать имя пользователя.', 'id deploy', ARRAY[]::text[], 'Так проверяют, в какие группы реально входит пользователь после изменений.', 'Users', 'easy'),
  ('groups-current-user', 'groups', 'Как показать группы текущего пользователя?', 'Команда вызывается без аргументов.', 'groups', ARRAY[]::text[], 'Это быстрый способ проверить членство в docker, sudo и других группах.', 'Users', 'easy'),
  ('chgrp-change-group', 'chgrp', 'Как поменять группу файла app.conf на deploy?', 'Сначала идет новая группа, затем имя файла.', 'chgrp deploy app.conf', ARRAY[]::text[], 'Полезно, когда доступ к файлу должен получить сервисный пользователь через группу.', 'Permissions', 'medium'),
  ('chmod-owner-read-write-exec', 'chmod', 'Как выдать владельцу файла script.sh права чтения, записи и выполнения символической записью?', 'Нужна запись с u и тремя правами.', 'chmod u+rwx script.sh', ARRAY[]::text[], 'Так можно точечно дать владельцу полный доступ, не меняя остальных.', 'Permissions', 'medium'),
  ('chmod-add-group-write', 'chmod', 'Как добавить группе право на запись в файл app.conf?', 'Нужна символическая запись с g и флагом write.', 'chmod g+w app.conf', ARRAY[]::text[], 'Удобно, когда несколько пользователей работают с одним конфигом через общую группу.', 'Permissions', 'medium'),
  ('find-empty-files', 'find', 'Как найти пустые файлы в текущей директории и ниже?', 'Нужны тип файла и размер 0.', 'find . -type f -empty', ARRAY[]::text[], 'Полезно для поиска случайно созданных пустых файлов после неудачных скриптов.', 'Search', 'medium'),
  ('find-delete-loggz', 'find', 'Как найти все файлы с расширением .log.gz в папке logs?', 'Нужны стартовая директория и фильтр по имени.', 'find logs -name "*.log.gz"', ARRAY['find logs -name ''*.log.gz''']::text[], 'Так можно быстро собрать все архивированные логи для переноса или чистки.', 'Search', 'medium'),
  ('ln-hard-link', 'ln', 'Как создать жесткую ссылку copy.txt на файл original.txt?', 'Для hard link флаг не нужен.', 'ln original.txt copy.txt', ARRAY[]::text[], 'Это полезно, когда нужно второе имя для того же inode в одной файловой системе.', 'File Management', 'hard'),
  ('ssh-connect-host', 'ssh', 'Как подключиться по SSH к серверу 192.168.1.20 под пользователем deploy?', 'Нужен формат пользователь@хост.', 'ssh deploy@192.168.1.20', ARRAY[]::text[], 'Базовый сценарий для входа на удаленный Linux-сервер.', 'Networking', 'easy'),
  ('scp-copy-file-server', 'scp', 'Как скопировать локальный файл app.conf на сервер в /etc/app/app.conf под пользователем deploy?', 'Нужны локальный файл и удаленный путь в формате user@host:path.', 'scp app.conf deploy@192.168.1.20:/etc/app/app.conf', ARRAY[]::text[], 'Так быстро закидывают конфиг на сервер без отдельного rsync.', 'Networking', 'medium'),
  ('rsync-sync-dir', 'rsync', 'Как синхронизировать папку public на сервер в /var/www/public с прогрессом и архивным режимом?', 'Нужны флаги archive, verbose и progress.', 'rsync -av --progress public/ deploy@192.168.1.20:/var/www/public/', ARRAY[]::text[], 'Это стандартный способ аккуратно обновлять статические файлы на сервере.', 'Networking', 'hard'),
  ('dig-short-domain', 'dig', 'Как получить только IP-адреса домена example.com без лишнего вывода?', 'Нужен short-режим.', 'dig +short example.com', ARRAY[]::text[], 'Полезно, когда нужно быстро проверить, куда сейчас резолвится домен.', 'Networking', 'medium'),
  ('nslookup-domain', 'nslookup', 'Как проверить DNS-резолвинг домена example.com?', 'Команде достаточно самого домена.', 'nslookup example.com', ARRAY[]::text[], 'Это удобный базовый способ посмотреть, отвечает ли DNS и какой IP возвращается.', 'Networking', 'easy'),
  ('ss-specific-port', 'ss', 'Как проверить, слушает ли кто-то порт 8080?', 'Нужны фильтр по listening sockets и grep по номеру порта.', 'ss -ltn | grep 8080', ARRAY['ss -ltn|grep 8080']::text[], 'Так быстро понимают, поднялся ли локальный сервис после запуска.', 'Networking', 'medium'),
  ('lsof-port-process', 'lsof', 'Как узнать, какой процесс использует TCP-порт 3000?', 'Нужен флаг i с tcp и номером порта.', 'lsof -i tcp:3000', ARRAY['lsof -iTCP:3000']::text[], 'Очень полезно, когда dev-сервер не стартует из-за занятого порта.', 'Networking', 'medium'),
  ('curl-download-file', 'curl', 'Как скачать файл по URL и сохранить его как archive.tar.gz?', 'Нужен флаг вывода в файл.', 'curl -o archive.tar.gz https://example.com/archive.tar.gz', ARRAY[]::text[], 'Так можно точно задать имя локального файла при скачивании.', 'Networking', 'medium'),
  ('wget-download-file', 'wget', 'Как скачать файл https://example.com/file.txt в текущую папку с исходным именем?', 'Команда может работать просто с URL.', 'wget https://example.com/file.txt', ARRAY[]::text[], 'Один из самых прямых способов скачать файл на сервер без браузера.', 'Networking', 'easy'),
  ('chmod-recursive-dir', 'chmod', 'Как рекурсивно выдать права 755 директории public и всему содержимому?', 'Нужен рекурсивный флаг и числовой режим.', 'chmod -R 755 public', ARRAY[]::text[], 'Иногда так быстро правят права на статику после копирования файлов.', 'Permissions', 'medium'),
  ('ps-sort-memory', 'ps', 'Как показать процессы, отсортированные по использованию памяти?', 'Нужен стандартный ps aux и сортировка по %mem в обратном порядке.', 'ps aux --sort=-%mem', ARRAY[]::text[], 'Помогает найти прожорливые процессы, когда серверу не хватает RAM.', 'Processes', 'hard'),
  ('pgrep-nginx', 'pgrep', 'Как найти PID процессов nginx по имени?', 'Команда принимает шаблон имени процесса.', 'pgrep nginx', ARRAY[]::text[], 'Это чище и короче, чем искать PID через ps и grep вручную.', 'Processes', 'medium'),
  ('pkill-node', 'pkill', 'Как завершить все процессы с именем node?', 'Команда принимает имя процесса и завершает совпадения.', 'pkill node', ARRAY[]::text[], 'Полезно, когда нужно быстро остановить все зависшие dev-серверы node.', 'Processes', 'medium'),
  ('kill-force-pid', 'kill', 'Как принудительно завершить процесс с PID 4242 сигналом KILL?', 'Нужен числовой сигнал 9.', 'kill -9 4242', ARRAY[]::text[], 'Это используют как крайнюю меру, когда обычный TERM уже не помогает.', 'Processes', 'medium'),
  ('uptime-show', 'uptime', 'Как показать время работы системы и текущую нагрузку?', 'Команда запускается без аргументов.', 'uptime', ARRAY[]::text[], 'Так можно быстро увидеть, как давно сервер не перезагружался и какова load average.', 'System Monitoring', 'easy'),
  ('vmstat-system', 'vmstat', 'Как посмотреть краткую статистику по памяти, процессам и IO?', 'Базовый запуск команды идет без флагов.', 'vmstat', ARRAY[]::text[], 'Полезно для быстрой грубой диагностики состояния системы без тяжелых тулов.', 'System Monitoring', 'medium'),
  ('journalctl-last-50', 'journalctl', 'Как показать последние 50 записей системного журнала?', 'Нужен флаг lines с количеством.', 'journalctl -n 50', ARRAY[]::text[], 'Так можно быстро посмотреть свежие события systemd без follow-режима.', 'Services', 'medium'),
  ('systemctl-enable', 'systemctl', 'Как включить автозапуск сервиса nginx при старте системы?', 'Нужна подкоманда enable, обычно через sudo.', 'sudo systemctl enable nginx', ARRAY[]::text[], 'После этого nginx будет автоматически стартовать после перезагрузки сервера.', 'Services', 'medium'),
  ('systemctl-stop', 'systemctl', 'Как остановить сервис nginx?', 'Используется подкоманда stop, как правило через sudo.', 'sudo systemctl stop nginx', ARRAY[]::text[], 'Нужно, когда сервис мешает тестам, деплою или требует ручного обслуживания.', 'Services', 'easy'),
  ('nginx-test-config', 'nginx', 'Как проверить конфигурацию nginx на синтаксические ошибки?', 'Нужен test-флаг, обычно через sudo.', 'sudo nginx -t', ARRAY[]::text[], 'Это полезно запускать перед reload или restart nginx после правок в конфиге.', 'Services', 'medium'),
  ('crontab-edit', 'crontab', 'Как открыть cron-таблицу текущего пользователя для редактирования?', 'Нужен флаг edit.', 'crontab -e', ARRAY[]::text[], 'Так добавляют периодические задания вроде бэкапов или очистки логов.', 'Automation', 'medium'),
  ('crontab-list', 'crontab', 'Как показать текущие cron-задачи пользователя?', 'Нужен флаг list.', 'crontab -l', ARRAY[]::text[], 'Удобно перед правкой понять, какие задания уже есть у пользователя.', 'Automation', 'easy'),
  ('chmod-octal-script-755', 'chmod', 'Как выдать скрипту deploy.sh права 755?', 'Используется числовой режим и имя файла.', 'chmod 755 deploy.sh', ARRAY[]::text[], 'Это типичный режим для исполняемых скриптов, доступных всем на чтение.', 'Permissions', 'easy'),
  ('mount-list', 'mount', 'Как вывести список смонтированных файловых систем?', 'Базовый запуск команды идет без аргументов.', 'mount', ARRAY[]::text[], 'Так можно быстро проверить, какие разделы и тома сейчас подключены к системе.', 'System Info', 'medium'),
  ('lsblk-list-block', 'lsblk', 'Как показать список блочных устройств и разделов?', 'Команда запускается без обязательных флагов.', 'lsblk', ARRAY[]::text[], 'Полезно после подключения нового диска или при разборе структуры разделов.', 'System Info', 'easy'),
  ('du-max-depth-one', 'du', 'Как показать размеры папок первого уровня внутри текущей директории в удобном формате?', 'Нужны human-readable и ограничение глубины.', 'du -h --max-depth=1', ARRAY[]::text[], 'Так можно быстро понять, какая подпапка занимает больше всего места.', 'System Monitoring', 'hard'),
  ('df-inode-usage', 'df', 'Как посмотреть использование inode на файловых системах?', 'Нужен специальный флаг вместо human-readable.', 'df -i', ARRAY[]::text[], 'Иногда место есть, а inode закончились — эта команда как раз помогает это увидеть.', 'System Monitoring', 'medium'),
  ('history-grep-ssh', 'history', 'Как найти в истории команд все вхождения ssh?', 'Нужен pipe и grep по слову ssh.', 'history | grep ssh', ARRAY['history|grep ssh']::text[], 'Удобно быстро вспомнить точную SSH-команду, которую вы уже запускали раньше.', 'Shell', 'easy'),
  ('alias-ll', 'alias', 'Как создать алиас ll для команды ls -la в текущей shell-сессии?', 'Нужно присвоение вида имя=''команда''.', 'alias ll=''ls -la''', ARRAY['alias ll="ls -la"']::text[], 'Так часто сокращают длинные команды для повседневной работы в терминале.', 'Shell', 'medium'),
  ('clear-terminal', 'clear', 'Как очистить текущий экран терминала?', 'Это очень короткая команда без флагов.', 'clear', ARRAY[]::text[], 'Полезно, когда после длинного вывода хочется быстро вернуть чистый экран.', 'Shell', 'easy')
on conflict (id) do update set
  command = excluded.command,
  question = excluded.question,
  hint = excluded.hint,
  answer = excluded.answer,
  accepted_answers = excluded.accepted_answers,
  example = excluded.example,
  category = excluded.category,
  difficulty = excluded.difficulty,
  updated_at = now();
